function rotateRight(arr, k) {
  const n = arr.length;
  if (n === 0) return arr;

  k %= n;
  if (k === 0) return arr;

  return arr.slice(-k).concat(arr.slice(0, n - k));
}

// Example
console.log(rotateRight([1, 2, 3, 4, 5], 2)); // [4, 5, 1, 2, 3]
```

In-place version:

```js
function rotateRightInPlace(arr, k) {
  const n = arr.length;
  if (n === 0) return arr;

  k %= n;
  reverse(arr, 0, n - 1);
  reverse(arr, 0, k - 1);
  reverse(arr, k, n - 1);
  return arr;
}

function reverse(arr, left, right) {
  while (left < right) {
    [arr[left], arr[right]] = [arr[right], arr[left]];
    left++;
    right--;
  }
}

// Example
const a = [1, 2, 3, 4, 5];
rotateRightInPlace(a, 2);
console.log(a); // [4, 5, 1, 2, 3]
