    for (let c = 0; c < cols; c++) {
      if (matrix[r][c] === 0) {
        zeroRows.add(r);
        zeroCols.add(c);
      }
    }
  }

  return matrix.map((row, r) =>
    row.map((value, c) =>
      zeroRows.has(r) || zeroCols.has(c) ? 0 : value
    )
  );
}
```

