```js
function parseQueryString(input) {
  if (input == null) return {};

  if (typeof input !== 'string') {
    throw new TypeError('Query string must be a string, null, or undefined');
  }

  let query = input.trim();
  if (query === '') return {};

  if (query.startsWith('?')) {
    query = query.slice(1);
  }

  if (query === '') return {};

  const result = {};

  for (const part of query.split('&')) {
    if (part === '') continue;

    const eqIndex = part.indexOf('=');
    const rawKey = eqIndex === -1 ? part : part.slice(0, eqIndex);
    const rawValue = eqIndex === -1 ? '' : part.slice(eqIndex + 1);

    const key = decodeQueryComponent(rawKey);
    const value = decodeQueryComponent(rawValue);

    if (Object.prototype.hasOwnProperty.call(result, key)) {
      if (Array.isArray(result[key])) {
        result[key].push(value);
      } else {
        result[key] = [result[key], value];
      }
    } else {
      result[key] = value;
    }
  }

  return result;
}

function decodeQueryComponent(value) {
  const normalized = value.replace(/\+/g, ' ');
  try {
    return decodeURIComponent(normalized);
  } catch {
    throw new Error(`Malformed escape sequence in query component: "${value}"`);
  }
}
```

