```javascript
function isPlainObject(value) {
  return Object.prototype.toString.call(value) === '[object Object]';
}

function mergeObjects(a, b) {
  const left = isPlainObject(a) ? a : {};
  const right = isPlainObject(b) ? b : {};
  const result = {};

  const keys = new Set([...Object.keys(left), ...Object.keys(right)]);

  for (const key of keys) {
    const hasLeft = Object.prototype.hasOwnProperty.call(left, key);
    const hasRight = Object.prototype.hasOwnProperty.call(right, key);

    if (!hasRight) {
      result[key] = cloneValue(left[key]);
      continue;
    }

    if (!hasLeft) {
      result[key] = cloneValue(right[key]);
      continue;
    }

    const leftValue = left[key];
    const rightValue = right[key];

    if (isPlainObject(leftValue) && isPlainObject(rightValue)) {
      result[key] = mergeObjects(leftValue, rightValue);
    } else {
      result[key] = cloneValue(rightValue);
    }
  }

  return result;
}

function cloneValue(value) {
  if (Array.isArray(value)) {
    return value.map(cloneValue);
  }

  if (isPlainObject(value)) {
    const copy = {};
    for (const key of Object.keys(value)) {
      copy[key] = cloneValue(value[key]);
    }
    return copy;
  }

  return value;
}
```

### Behavior
- Recursively merges only **plain objects**
- If both sides have a plain object at the same key, they are merged
- **Arrays are overwritten**, not merged
- Primitive conflicts are resolved in favor of the **second object**
- Missing keys are preserved
- Neither input is mutated

