```javascript
/**
 * Normalize a user-entered phone number into this format:
 *   +<countrycode><nationalnumber>[x<extension>]
 *
 * Examples:
 *   "(415) 555-2671"        -> "+14155552671"
 *   "+1 (415) 555-2671 x89" -> "+14155552671x89"
 *   "0044 20 7946 0958"     -> "+442079460958"
 *
 * Assumptions:
 * - Default country code is `1` when exactly 10 digits are provided.
 * - A leading `1` on 11-digit inputs is treated as the country code.
 * - `00` is accepted as an international prefix and converted to `+`.
 * - Extensions may be written as `ext`, `ext.`, `extension`, or `x`.
 * - Only digits are allowed in the extension.
 * - Formatting characters like spaces, dashes, dots, and parentheses are ignored.
 * - Alphabetic or other unexpected characters in the main number are invalid.
 * - Empty or whitespace-only input is invalid.
 */
function normalizePhoneNumber(input) {
  if (typeof input !== "string") {
    throw new TypeError("Phone number must be a string");
  }

  const raw = input.trim();
  if (!raw) {
    throw new Error("Phone number is empty");
  }

  const extMatch = raw.match(/(?:\bext\.?\b|\bextension\b|x)\s*(\d+)$/i);
  const extension = extMatch ? extMatch[1] : null;
  const numberPart = extMatch ? raw.slice(0, extMatch.index).trim() : raw;

  if (/[a-wyz]/i.test(numberPart)) {
    throw new Error("Phone number contains invalid characters");
  }

  let normalized = numberPart.replace(/[\s().-]/g, "");

  if (normalized.startsWith("00")) {
    normalized = `+${normalized.slice(2)}`;
  }

  if (normalized.startsWith("+")) {
    const internationalDigits = normalized.slice(1);
    if (!/^\d+$/.test(internationalDigits)) {
      throw new Error("Phone number contains invalid characters");
    }
    return extension ? `+${internationalDigits}x${extension}` : `+${internationalDigits}`;
  }

  if (!/^\d+$/.test(normalized)) {
    throw new Error("Phone number contains invalid characters");
  }

  if (normalized.length === 10) {
    normalized = `1${normalized}`;
  } else if (!(normalized.length === 11 && normalized.startsWith("1"))) {
    throw new Error("Phone number has an unsupported length");
  }

  return extension ? `+${normalized}x${extension}` : `+${normalized}`;
}
