  ["1.2.3", false],              // too few octets
  ["1.2.3.4.5", false],          // too many octets
  ["1.2.three.4", false],        // non-numeric octet
  ["1.-2.3.4", false],           // negative value
  ["256.1.2.3", false],          // > 255
  ["999.1.2.3", false],          // far > 255
  [" 1.2.3.4", false],           // surrounding whitespace
  ["1.2.3.4 ", false],           // surrounding whitespace
  ["", false],                   // empty string
  ["1..3.4", false],             // empty octet
  ["1.2.3.04", false],           // leading zero
];

