```js
function unflattenObject(input) {
  if (input == null || typeof input !== 'object' || Array.isArray(input)) {
    throw new TypeError('Input must be a plain object');
  }

  const result = {};

  for (const [flatKey, value] of Object.entries(input)) {
    if (typeof flatKey !== 'string' || flatKey.length === 0) {
      throw new Error(`Invalid key: "${flatKey}"`);
    }

    const parts = flatKey.split('.');

    if (parts.some(part => part.length === 0)) {
      throw new Error(`Invalid key with empty segment: "${flatKey}"`);
    }

    let cursor = result;

    for (let i = 0; i < parts.length; i++) {
      const part = parts[i];
      const isLeaf = i === parts.length - 1;

      if (isLeaf) {
        if (
          Object.prototype.hasOwnProperty.call(cursor, part) &&
          cursor[part] !== undefined &&
          typeof cursor[part] === 'object' &&
          cursor[part] !== null &&
          !Array.isArray(cursor[part])
        ) {
          throw new Error(`Conflicting path: "${flatKey}"`);
        }

        cursor[part] = value;
        continue;
      }

      if (!Object.prototype.hasOwnProperty.call(cursor, part)) {
        cursor[part] = {};
      } else {
        const existing = cursor[part];
        if (
          typeof existing !== 'object' ||
          existing === null ||
          Array.isArray(existing)
        ) {
          throw new Error(`Conflicting path: "${flatKey}"`);
        }
      }

      cursor = cursor[part];
    }
  }

  return result;
}
```

