assert.throws(
  () => unflattenObject({ 'a..b': 1 }),
  /Invalid key with empty segment/
);

// 9. invalid key: leading dot
assert.throws(
  () => unflattenObject({ '.a': 1 }),
  /Invalid key with empty segment/
);

// 10. invalid key: trailing dot
assert.throws(
  () => unflattenObject({ 'a.': 1 }),
  /Invalid key with empty segment/
);

