function rotateMatrix90Clockwise(matrix) {
  if (!Array.isArray(matrix)) {
    throw new TypeError('Input must be an array of arrays');
  }

  if (matrix.length === 0) {
    return [];
  }

  if (!matrix.every(Array.isArray)) {
    throw new TypeError('Input must be an array of arrays');
  }

  const rowLength = matrix[0].length;

  if (!matrix.every(row => row.length === rowLength)) {
    throw new TypeError('Matrix rows must all have the same length');
  }

  if (matrix.length !== rowLength) {
    throw new TypeError('Matrix must be square');
  }

  const n = matrix.length;
  const rotated = Array.from({ length: n }, () => Array(n));

  for (let row = 0; row < n; row++) {
    for (let col = 0; col < n; col++) {
      rotated[col][n - 1 - row] = matrix[row][col];
    }
  }

  return rotated;
}
```

