```js
function memoize(fn, { resolver } = {}) {
  if (typeof fn !== 'function') {
    throw new TypeError('Expected a function');
  }
  if (resolver != null && typeof resolver !== 'function') {
    throw new TypeError('Expected resolver to be a function');
  }

  const root = new Map();

  function getCacheNode(args) {
    let node = root;

    for (const arg of args) {
      const isObject = arg !== null && (typeof arg === 'object' || typeof arg === 'function');
      const key = isObject ? arg : `primitive:${typeof arg}:${String(arg)}`;
      const mapType = isObject ? 'object' : 'primitive';

      if (!node.has(mapType)) node.set(mapType, new Map());
      const nextMap = node.get(mapType);

      if (!nextMap.has(key)) nextMap.set(key, new Map());
      node = nextMap.get(key);
    }

    return node;
  }

  function memoized(...args) {
    const keyArgs = resolver ? [resolver.apply(this, args)] : args;
    const cacheNode = getCacheNode(keyArgs);

    if (cacheNode.has('value')) {
      return cacheNode.get('value');
    }

    if (cacheNode.has('error')) {
      throw cacheNode.get('error');
    }

    try {
      const result = fn.apply(this, args);
      cacheNode.set('value', result);
      return result;
    } catch (error) {
      cacheNode.set('error', error);
      throw error;
    }
  }

  memoized.clear = () => {
    root.clear();
  };

  return memoized;
}
```

### Cache key strategy

- **Primitive args**: keyed by `type + value`, so `1` and `"1"` are different.
- **Object/function args**: keyed by **reference identity**, not deep equality.
- **Argument order matters**: `(1, 2)` and `(2, 1)` are different keys.
- **Custom resolver**: optional `resolver(...args)` can override key generation when you want custom behavior.
- **Errors are cached too**: repeated calls with the same key rethrow the same error without re-executing.

This avoids JSON serialization pitfalls:
- circular objects
- unstable property order
- loss of functions/symbols/undefined
- accidental collisions

