      let threw = false;
      try {
        actual();
      } catch (err) {
        threw = true;
        if (err.message !== expectedMessage) {
          throw new Error(`Expected error message "${expectedMessage}", got "${err.message}"`);
        }
      }
      if (!threw) {
        throw new Error('Expected function to throw');
      }
    }
  };
}

// 1. Primitive arguments
test('caches primitive arguments', () => {
  let calls = 0;
  const fn = memoize((a, b) => {
    calls++;
    return a + b;
  });

  expect(fn(2, 3)).toBe(5);
  expect(fn(2, 3)).toBe(5);
  expect(calls).toBe(1);
});

// 2. Different primitive types do not collide
test('distinguishes primitive types', () => {
  let calls = 0;
  const fn = memoize((x) => {
    calls++;
    return typeof x;
  });

  expect(fn(1)).toBe('number');
  expect(fn('1')).toBe('string');
  expect(calls).toBe(2);
});

// 3. Object arguments by reference
test('caches object arguments by reference', () => {
  let calls = 0;
  const fn = memoize((obj) => {
    calls++;
    return obj.value * 2;
  });

  const obj = { value: 4 };
  expect(fn(obj)).toBe(8);
  expect(fn(obj)).toBe(8);
  expect(calls).toBe(1);
});

// 4. Different object references are different keys
test('treats different object references as different keys', () => {
  let calls = 0;
  const fn = memoize((obj) => {
    calls++;
    return obj.value * 2;
  });

  expect(fn({ value: 4 })).toBe(8);
  expect(fn({ value: 4 })).toBe(8);
  expect(calls).toBe(2);
});

// 5. Repeated calls with mixed arguments
test('caches repeated calls with multiple arguments', () => {
  let calls = 0;
  const fn = memoize((a, b, c) => {
    calls++;
    return `${a}-${b}-${c}`;
  });

  expect(fn(1, 'x', true)).toBe('1-x-true');
  expect(fn(1, 'x', true)).toBe('1-x-true');
  expect(calls).toBe(1);
});

// 6. Different argument order
test('treats different argument order as different keys', () => {
  let calls = 0;
  const fn = memoize((a, b) => {
    calls++;
    return a - b;
  });

  expect(fn(5, 2)).toBe(3);
  expect(fn(2, 5)).toBe(-3);
  expect(fn(5, 2)).toBe(3);
  expect(calls).toBe(2);
});

// 7. Undefined result
test('caches undefined results', () => {
  let calls = 0;
  const fn = memoize((x) => {
    calls++;
    if (x > 0) return undefined;
    return 'nope';
  });

  expect(fn(1)).toBe(undefined);
  expect(fn(1)).toBe(undefined);
  expect(calls).toBe(1);
});

// 8. Thrown errors are cached
test('caches thrown errors', () => {
  let calls = 0;
  const fn = memoize((x) => {
    calls++;
    if (x === 0) throw new Error('boom');
    return x;
  });

  expect(() => fn(0)).toThrowMessage('boom');
  expect(() => fn(0)).toThrowMessage('boom');
  expect(calls).toBe(1);
});

// 9. Preserves this context
test('preserves this binding', () => {
  let calls = 0;
  const obj = {
    factor: 3,
    multiply: memoize(function (x) {
      calls++;
      return x * this.factor;
    })
  };

  expect(obj.multiply(4)).toBe(12);
  expect(obj.multiply(4)).toBe(12);
  expect(calls).toBe(1);
});

// 10. Zero-argument function
test('caches zero-argument calls', () => {
  let calls = 0;
  const fn = memoize(() => {
    calls++;
    return 42;
  });

  expect(fn()).toBe(42);
  expect(fn()).toBe(42);
  expect(calls).toBe(1);
});

// 11. Custom resolver
test('supports custom resolver', () => {
  let calls = 0;
  const fn = memoize(
    (a, b) => {
      calls++;
      return a + b;
    },
    {
      resolver(a, b) {
        return `${Math.min(a, b)}:${Math.max(a, b)}`;
      }
    }
  );

  expect(fn(2, 5)).toBe(7);
  expect(fn(5, 2)).toBe(7);
  expect(calls).toBe(1);
});

// 12. Can clear cache
test('clear removes cached entries', () => {
  let calls = 0;
  const fn = memoize((x) => {
    calls++;
    return x * 2;
  });

  expect(fn(3)).toBe(6);
  expect(fn(3)).toBe(6);
  fn.clear();
  expect(fn(3)).toBe(6);
  expect(calls).toBe(2);
});
```

### Notes

- If you want **deep-equal object caching** instead of reference-based caching, use a custom `resolver`, but define serialization rules carefully.
- Current behavior is usually the safest default for general-purpose memoization.

