function diffArrays(before, after) {
  const beforeCounts = new Map();
  const afterCounts = new Map();

  for (const item of before) {
    beforeCounts.set(item, (beforeCounts.get(item) || 0) + 1);
  }

  for (const item of after) {
    afterCounts.set(item, (afterCounts.get(item) || 0) + 1);
  }

  const allValues = new Set([...beforeCounts.keys(), ...afterCounts.keys()]);
  const added = [];
  const removed = [];
  const unchanged = [];

  for (const value of allValues) {
    const beforeCount = beforeCounts.get(value) || 0;
    const afterCount = afterCounts.get(value) || 0;
    const sharedCount = Math.min(beforeCount, afterCount);

    for (let i = 0; i < sharedCount; i++) unchanged.push(value);
    for (let i = 0; i < afterCount - sharedCount; i++) added.push(value);
    for (let i = 0; i < beforeCount - sharedCount; i++) removed.push(value);
  }

  return { added, removed, unchanged };
}
```

### Multiplicity behavior
Multiplicity **does matter**.

That means:
- `['a']` vs `['a', 'a']` → one `'a'` is `unchanged`, one `'a'` is `added`
- `['x', 'x']` vs `['x']` → one `'x'` is `unchanged`, one `'x'` is `removed`

This treats arrays as **multisets** rather than simple sets.

---

