function formatDuration(input) {
  if (typeof input !== "number" || Number.isNaN(input)) {
    throw new TypeError("Input must be a valid number");
  }

  if (!Number.isFinite(input)) {
    throw new RangeError("Input must be finite");
  }

  if (input < 0) {
    throw new RangeError("Input cannot be negative");
  }

  if (input === 0) {
    return "0 seconds";
  }

  const hasFraction = !Number.isInteger(input);
  const totalSeconds = Math.floor(input);

  const units = [
    { label: "hour", value: 3600 },
    { label: "minute", value: 60 },
    { label: "second", value: 1 },
  ];

  let remaining = totalSeconds;
  const parts = [];

  for (const unit of units) {
    const count = Math.floor(remaining / unit.value);
    remaining %= unit.value;

    if (count > 0) {
      parts.push(`${count} ${unit.label}${count === 1 ? "" : "s"}`);
    }
  }

  if (hasFraction) {
    const fractional = input - totalSeconds;
    if (fractional > 0) {
      const ms = Math.round(fractional * 1000);
      if (ms > 0) {
        parts.push(`${ms} millisecond${ms === 1 ? "" : "s"}`);
      }
    }
  }

  if (parts.length === 1) {
    return parts[0];
  }

  return `${parts.slice(0, -1).join(", ")} and ${parts[parts.length - 1]}`;
}
```

