function slugify(input) {
  if (input == null) return '';

  const transliterations = {
    // Latin accents / symbols
    ß: 'ss',
    Æ: 'ae',
    æ: 'ae',
    Ø: 'o',
    ø: 'o',
    Å: 'a',
    å: 'a',
    Đ: 'd',
    đ: 'd',
    Þ: 'th',
    þ: 'th',
    Ł: 'l',
    ł: 'l',
    Œ: 'oe',
    œ: 'oe',

    // Greek
    Α: 'a', Β: 'b', Γ: 'g', Δ: 'd', Ε: 'e', Ζ: 'z', Η: 'i', Θ: 'th', Ι: 'i', Κ: 'k',
    Λ: 'l', Μ: 'm', Ν: 'n', Ξ: 'x', Ο: 'o', Π: 'p', Ρ: 'r', Σ: 's', Τ: 't', Υ: 'y',
    Φ: 'f', Χ: 'ch', Ψ: 'ps', Ω: 'o',
    α: 'a', β: 'b', γ: 'g', δ: 'd', ε: 'e', ζ: 'z', η: 'i', θ: 'th', ι: 'i', κ: 'k',
    λ: 'l', μ: 'm', ν: 'n', ξ: 'x', ο: 'o', π: 'p', ρ: 'r', σ: 's', ς: 's', τ: 't',
    υ: 'y', φ: 'f', χ: 'ch', ψ: 'ps', ω: 'o',

    // Cyrillic
    А: 'a', Б: 'b', В: 'v', Г: 'g', Д: 'd', Е: 'e', Ё: 'e', Ж: 'zh', З: 'z', И: 'i',
    Й: 'i', К: 'k', Л: 'l', М: 'm', Н: 'n', О: 'o', П: 'p', Р: 'r', С: 's', Т: 't',
    У: 'u', Ф: 'f', Х: 'kh', Ц: 'ts', Ч: 'ch', Ш: 'sh', Щ: 'shch', Ъ: '', Ы: 'y',
    Ь: '', Э: 'e', Ю: 'yu', Я: 'ya',
    а: 'a', б: 'b', в: 'v', г: 'g', д: 'd', е: 'e', ё: 'e', ж: 'zh', з: 'z', и: 'i',
    й: 'i', к: 'k', л: 'l', м: 'm', н: 'n', о: 'o', п: 'p', р: 'r', с: 's', т: 't',
    у: 'u', ф: 'f', х: 'kh', ц: 'ts', ч: 'ch', ш: 'sh', щ: 'shch', ъ: '', ы: 'y',
    ь: '', э: 'e', ю: 'yu', я: 'ya',
  };

  let text = String(input).trim();

  if (!text) return '';

  text = Array.from(text, char => transliterations[char] ?? char).join('');

  // Decompose accented chars, then remove combining marks.
  text = text.normalize('NFKD').replace(/[\u0300-\u036f]/g, '');

  // Lowercase for stable slug output.
  text = text.toLowerCase();

  // Replace apostrophes with nothing so "don't" -> "dont"
  text = text.replace(/['’]/g, '');

  // Replace any run of non-letter/number chars with a hyphen.
  text = text.replace(/[^\p{Letter}\p{Number}]+/gu, '-');

  // Remove leading/trailing hyphens.
  text = text.replace(/^-+|-+$/g, '');

  return text;
}
```

### Transliteration rules
- **Latin accented characters**: normalize to base letters where possible (`é → e`, `ñ → n`, `ü → u`).
- **Special Latin letters**: explicit mappings for characters not handled well by normalization (`ß → ss`, `æ → ae`, `œ → oe`, `ø → o`, `ł → l`).
- **Greek**: transliterated to approximate Latin equivalents (`γειά → geia`).
- **Cyrillic**: transliterated to approximate Latin equivalents (`Привет → privet`).
- **Other non-Latin scripts**:
  - If covered by the explicit map, transliterate.
  - If not covered, preserve letters because they are valid in modern URL paths.
- **Emoji and symbols**: removed.
- **Whitespace / punctuation / separators**: collapsed into single hyphens.
- **Existing hyphens**: preserved as separators, but repeated separators collapse to one.
- **Apostrophes**: removed instead of becoming separators.

