function compareSemver(a, b) {
  const parse = (input) => {
    if (typeof input !== "string" || input.trim() === "") {
      throw new Error("Invalid version");
    }

    const match = input.match(
      /^(\d+)(?:\.(\d+))?(?:\.(\d+))?(?:-([0-9A-Za-z-]+(?:\.[0-9A-Za-z-]+)*))?$/
    );

    if (!match) {
      throw new Error(`Invalid version: ${input}`);
    }

    const [, major, minor = "0", patch = "0", prerelease] = match;

    const normalizeNumber = (value) => String(Number(value));
    const nums = [major, minor, patch].map(normalizeNumber);

    return {
      major: Number(nums[0]),
      minor: Number(nums[1]),
      patch: Number(nums[2]),
      prerelease: prerelease ? prerelease.split(".") : null,
    };
  };

  const comparePrerelease = (aParts, bParts) => {
    if (!aParts && !bParts) return 0;
    if (!aParts) return 1;
    if (!bParts) return -1;

    const len = Math.max(aParts.length, bParts.length);

    for (let i = 0; i < len; i++) {
      const aPart = aParts[i];
      const bPart = bParts[i];

      if (aPart === undefined) return -1;
      if (bPart === undefined) return 1;

      const aNumeric = /^\d+$/.test(aPart);
      const bNumeric = /^\d+$/.test(bPart);

      if (aNumeric && bNumeric) {
        const diff = Number(aPart) - Number(bPart);
        if (diff !== 0) return diff < 0 ? -1 : 1;
        continue;
      }

      if (aNumeric && !bNumeric) return -1;
      if (!aNumeric && bNumeric) return 1;

      if (aPart < bPart) return -1;
      if (aPart > bPart) return 1;
    }

    return 0;
  };

  const va = parse(a);
  const vb = parse(b);

  if (va.major !== vb.major) return va.major < vb.major ? -1 : 1;
  if (va.minor !== vb.minor) return va.minor < vb.minor ? -1 : 1;
  if (va.patch !== vb.patch) return va.patch < vb.patch ? -1 : 1;

  return comparePrerelease(va.prerelease, vb.prerelease);
}
```

