```js
// Base-1024 formatter.
// Examples:
// formatBytes(0)            => "0 B"
// formatBytes(1024)         => "1 KB"
// formatBytes(1536)         => "1.5 KB"
// formatBytes(-1048576)     => "-1 MB"

function formatBytes(value) {
  if (typeof value !== 'number' || !Number.isFinite(value)) {
    throw new TypeError('formatBytes expects a finite number');
  }

  const units = ['B', 'KB', 'MB', 'GB', 'TB', 'PB', 'EB'];
  const sign = value < 0 ? '-' : '';
  let bytes = Math.abs(value);

  if (bytes === 0) return '0 B';

  let unitIndex = 0;
  while (bytes >= 1024 && unitIndex < units.length - 1) {
    bytes /= 1024;
    unitIndex++;
  }

  const rounded =
    bytes >= 100 || Number.isInteger(bytes)
      ? String(Math.round(bytes * 100) / 100)
      : String(Math.round(bytes * 100) / 100);

  return `${sign}${rounded.replace(/\.0+$/, '').replace(/(\.\d*[1-9])0+$/, '$1')} ${units[unitIndex]}`;
}
```

