function mergeIntervals(intervals) {
  if (!Array.isArray(intervals)) {
    throw new TypeError('Expected an array of intervals');
  }

  if (intervals.length === 0) {
    return [];
  }

  const normalized = intervals.map((interval, index) => {
    if (
      !Array.isArray(interval) ||
      interval.length !== 2 ||
      !Number.isFinite(interval[0]) ||
      !Number.isFinite(interval[1])
    ) {
      throw new TypeError(`Invalid interval at index ${index}`);
    }

    const [start, end] = interval;

    if (start > end) {
      throw new RangeError(`Interval start must be <= end at index ${index}`);
    }

    return [start, end];
  });

  normalized.sort((a, b) => a[0] - b[0] || a[1] - b[1]);

  const merged = [normalized[0].slice()];

  for (let i = 1; i < normalized.length; i++) {
    const [start, end] = normalized[i];
    const last = merged[merged.length - 1];

    if (start <= last[1]) {
      last[1] = Math.max(last[1], end);
    } else {
      merged.push([start, end]);
    }
  }

  return merged;
}
```

