```js
function wrapText(text, width) {
  if (!Number.isInteger(width) || width < 1) {
    throw new Error("width must be a positive integer");
  }

  if (text === "") return "";

  const lines = text.split("\n");

  return lines
    .map((line) => wrapSingleLine(line, width))
    .join("\n");
}

function wrapSingleLine(line, width) {
  const trimmedRight = line.replace(/[ \t]+$/g, "");

  if (trimmedRight === "") return "";

  const words = trimmedRight.match(/\S+/g) || [];
  const out = [];
  let current = "";

  for (const word of words) {
    if (current === "") {
      current = word;
      continue;
    }

    if (current.length + 1 + word.length <= width) {
      current += " " + word;
      continue;
    }

    out.push(current);

    if (word.length <= width) {
      current = word;
      continue;
    }

    let rest = word;
    while (rest.length > width) {
      out.push(rest.slice(0, width));
      rest = rest.slice(width);
    }
    current = rest;
  }

  if (current !== "") out.push(current);

  return out.join("\n");
}
```

### Defined behavior
- Collapses runs of spaces/tabs between words to a single space.
- Trims trailing spaces/tabs on each input line.
- Preserves existing `\n` line breaks exactly.
- Treats punctuation as part of a word.
- Splits words longer than `width` into chunks of size `width`.
- Empty or whitespace-only lines stay empty.
- Throws on invalid `width` values.

