function escapeHtml(input) {
  if (input == null) return '';

  return String(input).replace(/&(?:#\d+|#x[0-9a-f]+|[a-z]+);|[&<>"']/gi, (match) => {
    switch (match) {
      case '&':
        return '&amp;';
      case '<':
        return '&lt;';
      case '>':
        return '&gt;';
      case '"':
        return '&quot;';
      case "'":
        return '&#39;';
      default:
        return match;
    }
  });
}
