function buildTree(nodes) {
  if (!Array.isArray(nodes)) {
    throw new TypeError("nodes must be an array");
  }

  const byId = new Map();
  const treeNodes = new Map();
  const roots = [];
  const missingParents = [];
  const duplicateIds = [];
  const cycleIds = new Set();

  for (let i = 0; i < nodes.length; i++) {
    const node = nodes[i];

    if (!node || typeof node !== "object" || Array.isArray(node)) {
      throw new TypeError(`node at index ${i} must be an object`);
    }

    if (!Object.prototype.hasOwnProperty.call(node, "id")) {
      throw new Error(`node at index ${i} is missing id`);
    }

    const { id } = node;
    if (id === null || id === undefined || id === "") {
      throw new Error(`node at index ${i} has invalid id`);
    }

    if (byId.has(id)) {
      duplicateIds.push(id);
      continue;
    }

    byId.set(id, node);
    treeNodes.set(id, { ...node, children: [] });
  }

  if (duplicateIds.length > 0) {
    throw new Error(`duplicate ids: ${duplicateIds.join(", ")}`);
  }

  function detectCycle(startId) {
    const seenInPath = new Set();
    let currentId = startId;

    while (currentId !== null && currentId !== undefined) {
      if (seenInPath.has(currentId)) {
        for (const id of seenInPath) cycleIds.add(id);
        return true;
      }

      seenInPath.add(currentId);

      const current = byId.get(currentId);
      if (!current) return false;

      const parentId = current.parentId;
      if (parentId === null || parentId === undefined) return false;

      if (!byId.has(parentId)) return false;

      currentId = parentId;
    }

    return false;
  }

  for (const id of byId.keys()) {
    detectCycle(id);
  }

  if (cycleIds.size > 0) {
    throw new Error(`cycle detected involving ids: ${[...cycleIds].join(", ")}`);
  }

  for (const node of byId.values()) {
    const current = treeNodes.get(node.id);
    const parentId = node.parentId;

    if (parentId === null || parentId === undefined) {
      roots.push(current);
      continue;
    }

    const parent = treeNodes.get(parentId);
    if (!parent) {
      missingParents.push({ id: node.id, parentId });
      roots.push(current);
      continue;
    }

    parent.children.push(current);
  }

  return {
    roots,
    missingParents,
  };
}
