function parseStrictIsoDate(input, options = {}) {
  const { structured = false } = options;

  if (typeof input !== 'string') {
    throw new TypeError('Date input must be a string');
  }

  if (input !== input.trim() || input === '') {
    throw new Error('Date must be a non-empty string with no surrounding whitespace');
  }

  const match = /^(\d{4})-(\d{2})-(\d{2})$/.exec(input);
  if (!match) {
    throw new Error('Date must be in strict YYYY-MM-DD format');
  }

  const year = Number(match[1]);
  const month = Number(match[2]);
  const day = Number(match[3]);

  if (month < 1 || month > 12) {
    throw new Error('Invalid month');
  }

  const daysInMonth = [
    31,
    isLeapYear(year) ? 29 : 28,
    31,
    30,
    31,
    30,
    31,
    31,
    30,
    31,
    30,
    31,
  ];

  if (day < 1 || day > daysInMonth[month - 1]) {
    throw new Error('Invalid day');
  }

  if (structured) {
    return { year, month, day };
  }

  const date = new Date(year, month - 1, day);

  if (
    date.getFullYear() !== year ||
    date.getMonth() !== month - 1 ||
    date.getDate() !== day
  ) {
    throw new Error('Invalid calendar date');
  }

  return date;
}

function isLeapYear(year) {
  return year % 4 === 0 && (year % 100 !== 0 || year % 400 === 0);
}
