    throw new TypeError('Both paths must be strings');
  }

  const hasBackslash = from.includes('\\') || to.includes('\\');
  const sep = hasBackslash ? '\\' : '/';

  const isAbsolute = (p) => {
    if (sep === '\\') {
      return /^[A-Za-z]:[\\/]/.test(p) || /^\\\\[^\\]+\\[^\\]+/.test(p);
    }
    return p.startsWith('/');
  };

  if (!isAbsolute(from) || !isAbsolute(to)) {
    throw new Error('Both paths must be absolute');
  }

  const normalize = (p) => {
    let s = p.replace(/[\\/]+/g, sep);

    if (sep === '\\') {
      const driveMatch = s.match(/^([A-Za-z]:)(\\.*)?$/);
      if (driveMatch) {
        const drive = driveMatch[1];
        const rest = (driveMatch[2] || '\\').replace(/\\+$/g, '');
        return {
          root: drive + '\\',
          parts: rest === '' || rest === '\\' ? [] : rest.slice(1).split('\\'),
        };
      }

      const uncMatch = s.match(/^(\\\\[^\\]+\\[^\\]+)(\\.*)?$/);
      if (uncMatch) {
        const root = uncMatch[1];
        const rest = (uncMatch[2] || '\\').replace(/\\+$/g, '');
        return {
          root: root + '\\',
          parts: rest === '' || rest === '\\' ? [] : rest.slice(1).split('\\'),
        };
      }

      throw new Error('Invalid absolute Windows path');
    }

    s = s.replace(/\/+$/g, '');
    return {
      root: '/',
      parts: s === '' ? [] : s.slice(1).split('/'),
    };
  };

  const fromNorm = normalize(from);
  const toNorm = normalize(to);

  if (fromNorm.root.toLowerCase() !== toNorm.root.toLowerCase()) {
    throw new Error('Paths must share the same root');
  }

  let i = 0;
  while (
    i < fromNorm.parts.length &&
    i < toNorm.parts.length &&
    fromNorm.parts[i] === toNorm.parts[i]
  ) {
    i++;
  }

  const up = new Array(fromNorm.parts.length - i).fill('..');
  const down = toNorm.parts.slice(i);
  const result = [...up, ...down].join(sep);

  return result || '.';
}
