/**
 * Stable multi-key sort for arrays of objects.
 *
 * Assumptions / behavior:
 * - Does not mutate the input array.
 * - Sorting is stable: if all compared keys are equal, original order is preserved.
 * - Missing fields (`undefined` or absent) sort after defined values in ascending order
 *   and before defined values in descending order.
 * - `null` is treated as a normal value, distinct from `undefined`.
 * - Mixed primitive types are ordered by type first using this rank:
 *   number < bigint < string < boolean < symbol < object < function
 * - Values of the same type are compared naturally:
 *   - number/bigint: numeric comparison
 *   - string: localeCompare
 *   - boolean: false < true
 *   - others: String(value) comparison
 * - Rules can be passed as:
 *   - "field"                  => ascending
 *   - "-field"                 => descending
 *   - { key: "field", dir: "asc" | "desc" }
 */
function sortByMany(items, rules) {
  if (!Array.isArray(items)) {
    throw new TypeError("items must be an array");
  }

  if (!Array.isArray(rules) || rules.length === 0) {
    return items.slice();
  }

  const normalizedRules = rules.map((rule) => {
    if (typeof rule === "string") {
      if (!rule) throw new TypeError("sort rule string cannot be empty");
      return rule.startsWith("-")
        ? { key: rule.slice(1), dir: "desc" }
        : { key: rule, dir: "asc" };
    }

    if (
      !rule ||
      typeof rule !== "object" ||
      typeof rule.key !== "string" ||
      (rule.dir !== "asc" && rule.dir !== "desc")
    ) {
      throw new TypeError(
        'each rule must be a string or { key: string, dir: "asc" | "desc" }'
      );
    }

    return rule;
  });

  return items
    .map((item, index) => ({ item, index }))
    .sort((a, b) => {
      for (const { key, dir } of normalizedRules) {
        const cmp = compareValues(a.item?.[key], b.item?.[key]);
        if (cmp !== 0) {
          return dir === "desc" ? -cmp : cmp;
        }
      }

      return a.index - b.index;
    })
    .map((entry) => entry.item);
}

function compareValues(a, b) {
  const aMissing = a === undefined;
  const bMissing = b === undefined;

  if (aMissing && bMissing) return 0;
  if (aMissing) return 1;
  if (bMissing) return -1;

  const typeA = typeof a;
  const typeB = typeof b;

  if (typeA !== typeB) {
    return typeRank(typeA) - typeRank(typeB);
  }

  switch (typeA) {
    case "number":
      return a - b;
    case "bigint":
      return a < b ? -1 : a > b ? 1 : 0;
    case "string":
      return a.localeCompare(b);
    case "boolean":
      return Number(a) - Number(b);
    default: {
      const sa = String(a);
      const sb = String(b);
      return sa.localeCompare(sb);
    }
  }
}

function typeRank(type) {
  switch (type) {
    case "number":
      return 1;
    case "bigint":
      return 2;
    case "string":
      return 3;
    case "boolean":
      return 4;
    case "symbol":
      return 5;
    case "object":
      return 6;
    case "function":
      return 7;
    case "undefined":
      return 8;
    default:
      return 99;
  }
}
