from collections import Counter
import unittest


def min_window_substring(s: str, t: str) -> str:
    if not s or not t:
        return ""

    need = Counter(t)
    missing = len(t)
    left = 0
    best_start = 0
    best_len = float("inf")

    for right, ch in enumerate(s):
        if need[ch] > 0:
            missing -= 1
        need[ch] -= 1

        while missing == 0:
            window_len = right - left + 1
            if window_len < best_len:
                best_start = left
                best_len = window_len

            left_ch = s[left]
            need[left_ch] += 1
            if need[left_ch] > 0:
                missing += 1
            left += 1

    return "" if best_len == float("inf") else s[best_start:best_start + best_len]


class TestMinWindowSubstring(unittest.TestCase):
    def test_standard_case(self):
        self.assertEqual(min_window_substring("ADOBECODEBANC", "ABC"), "BANC")

    def test_no_match(self):
        self.assertEqual(min_window_substring("hello", "worldz"), "")

    def test_exact_match(self):
        self.assertEqual(min_window_substring("ABC", "ABC"), "ABC")

    def test_repeated_characters_in_t(self):
        self.assertEqual(min_window_substring("AAABBC", "AABC"), "AABBC")

    def test_empty_s(self):
        self.assertEqual(min_window_substring("", "ABC"), "")

    def test_empty_t(self):
        self.assertEqual(min_window_substring("ABC", ""), "")

    def test_case_sensitivity(self):
        self.assertEqual(min_window_substring("aAAbBc", "ABC"), "")

    def test_multiple_valid_windows(self):
        self.assertEqual(min_window_substring("abdcab", "ab"), "ab")

    def test_entire_string_needed_due_to_multiplicity(self):
        self.assertEqual(min_window_substring("aaflslflsldkalskaaa", "aaa"), "aaa")

    def test_single_character_match(self):
        self.assertEqual(min_window_substring("xyz", "y"), "y")


if __name__ == "__main__":
    unittest.main()
```

### Notes
- Time: `O(len(s) + len(t))`
- Space: `O(len(unique chars in t))`
- Efficiently uses a sliding window with character counts.
- Returns `""` when no valid window exists.

