function pairsToQueryString(pairs) {
  if (!Array.isArray(pairs) || pairs.length === 0) return "";

  return pairs
    .map((pair) => {
      if (!Array.isArray(pair) || pair.length !== 2) {
        throw new TypeError("Each item must be a [name, value] pair");
      }

      const [name, value] = pair;

      const encodedName = encodeURIComponent(String(name));
      const encodedValue = encodeURIComponent(String(value));

      return `${encodedName}=${encodedValue}`;
    })
    .join("&");
}
```

### Encoding behavior
- Uses `encodeURIComponent` for both names and values.
- Spaces become `%20` (not `+`).
- Repeated field names are preserved in order.
- Empty names are allowed: `["", "x"]` → `=x`
- Empty values are allowed: `["a", ""]` → `a=`
- `null` and `undefined` are stringified as `"null"` and `"undefined"` unless you want different semantics.
- Empty input returns `""`.
- Invalid entries that are not exactly `[name, value]` throw `TypeError`.

