  const count = sorted.length;
  const min = sorted[0];
  const max = sorted[count - 1];
  const sum = sorted.reduce((acc, n) => acc + n, 0);
  const mean = sum / count;

  const median =
    count % 2 === 1
      ? sorted[Math.floor(count / 2)]
      : (sorted[count / 2 - 1] + sorted[count / 2]) / 2;

  const freq = new Map();
  for (const n of numbers) {
    freq.set(n, (freq.get(n) || 0) + 1);
  }

  let highestFreq = 0;
  for (const value of freq.values()) {
    if (value > highestFreq) highestFreq = value;
  }

  const modes = [...freq.entries()]
    .filter(([, count]) => count === highestFreq)
    .map(([value]) => value)
    .sort((a, b) => a - b);

  const mode = highestFreq === 1 || modes.length > 1 ? null : modes[0];

