function nearestPalindrome(input) {
  if (typeof input !== 'string' || !/^[0-9]+$/.test(input) || input.length === 0) {
    throw new TypeError('Input must be a non-empty positive integer string');
  }
  if (input === '0') {
    throw new TypeError('Input must represent a positive integer');
  }

  const stripLeadingZeros = (s) => {
    const stripped = s.replace(/^0+/, '');
    return stripped === '' ? '0' : stripped;
  };

  const compareNumStr = (a, b) => {
    a = stripLeadingZeros(a);
    b = stripLeadingZeros(b);
    if (a.length !== b.length) return a.length < b.length ? -1 : 1;
    if (a === b) return 0;
    return a < b ? -1 : 1;
  };

  const addOne = (s) => {
    let carry = 1;
    let out = '';
    for (let i = s.length - 1; i >= 0; i--) {
      const digit = s.charCodeAt(i) - 48 + carry;
      if (digit >= 10) {
        out = '0' + out;
        carry = 1;
      } else {
        out = String.fromCharCode(48 + digit) + out;
        carry = 0;
      }
    }
    return carry ? '1' + out : out;
  };

  const subOne = (s) => {
    if (s === '0') return '0';
    let borrow = 1;
    let out = '';
    for (let i = s.length - 1; i >= 0; i--) {
      let digit = s.charCodeAt(i) - 48 - borrow;
      if (digit < 0) {
        digit += 10;
        borrow = 1;
      } else {
        borrow = 0;
      }
      out = String.fromCharCode(48 + digit) + out;
    }
    return stripLeadingZeros(out);
  };

  const absDiff = (a, b) => {
    const cmp = compareNumStr(a, b);
    if (cmp === 0) return '0';
    let bigger = cmp > 0 ? a : b;
    let smaller = cmp > 0 ? b : a;

    bigger = bigger.split('');
    smaller = smaller.padStart(bigger.length, '0');

    let borrow = 0;
    let out = '';
    for (let i = bigger.length - 1; i >= 0; i--) {
      let digit = (bigger[i].charCodeAt(0) - 48) - (smaller[i].charCodeAt(0) - 48) - borrow;
      if (digit < 0) {
        digit += 10;
        borrow = 1;
      } else {
        borrow = 0;
      }
      out = String.fromCharCode(48 + digit) + out;
    }
    return stripLeadingZeros(out);
  };

  const makePalindromeFromPrefix = (prefix, totalLength) => {
    const left = prefix;
    const mirrorSource = totalLength % 2 === 0 ? prefix : prefix.slice(0, -1);
    return left + mirrorSource.split('').reverse().join('');
  };

  const n = input.length;
  const prefixLen = Math.ceil(n / 2);
  const prefix = input.slice(0, prefixLen);

  const candidates = new Set();

  candidates.add(makePalindromeFromPrefix(prefix, n));
  candidates.add(makePalindromeFromPrefix(addOne(prefix), n));
  candidates.add(makePalindromeFromPrefix(subOne(prefix).padStart(prefixLen, '0'), n));

  candidates.add('9'.repeat(n - 1) || '0');
  candidates.add('1' + '0'.repeat(n - 1) + '1');

  candidates.delete(input);
  candidates.delete('0');

  let best = null;
  let bestDiff = null;

  for (const candidate of candidates) {
    if (!/^[0-9]+$/.test(candidate)) continue;
    const normalized = stripLeadingZeros(candidate);
    if (normalized === '0') continue;

    const diff = absDiff(input, normalized);

    if (
      best === null ||
      compareNumStr(diff, bestDiff) < 0 ||
      (compareNumStr(diff, bestDiff) === 0 && compareNumStr(normalized, best) < 0)
    ) {
      best = normalized;
      bestDiff = diff;
    }
  }

  return best;
}
