import unittest


def eval_rpn(tokens):
    """
    Evaluate an arithmetic expression in Reverse Polish Notation.

    Rules:
    - Supported operators: +, -, *, /
    - Operands must be valid integers (including negative numbers like "-11")
    - Division uses integer truncation toward zero
    - Raises ValueError for:
        - empty input
        - invalid tokens
        - insufficient operands
        - extra operands left after evaluation
    """
    if not tokens:
        raise ValueError("empty input")

    stack = []

    for token in tokens:
        if token in {"+", "-", "*", "/"}:
            if len(stack) < 2:
                raise ValueError("insufficient operands")
            b = stack.pop()
            a = stack.pop()

            if token == "+":
                stack.append(a + b)
            elif token == "-":
                stack.append(a - b)
            elif token == "*":
                stack.append(a * b)
            else:
                if b == 0:
                    raise ValueError("division by zero")
                stack.append(int(a / b))  # truncates toward zero
        else:
            try:
                stack.append(int(token))
            except (TypeError, ValueError):
                raise ValueError(f"invalid token: {token}")

    if len(stack) != 1:
        raise ValueError("extra operands")

    return stack[0]


class TestEvalRpn(unittest.TestCase):
    def test_addition(self):
        self.assertEqual(eval_rpn(["2", "3", "+"]), 5)

    def test_subtraction(self):
        self.assertEqual(eval_rpn(["10", "4", "-"]), 6)

    def test_multiplication(self):
        self.assertEqual(eval_rpn(["6", "7", "*"]), 42)

    def test_division_truncates_toward_zero(self):
        self.assertEqual(eval_rpn(["7", "3", "/"]), 2)

    def test_negative_numbers(self):
        self.assertEqual(eval_rpn(["-4", "2", "*"]), -8)

    def test_negative_division_truncates_toward_zero(self):
        self.assertEqual(eval_rpn(["-7", "3", "/"]), -2)

    def test_invalid_token(self):
        with self.assertRaisesRegex(ValueError, "invalid token"):
            eval_rpn(["2", "x", "+"])

    def test_insufficient_operands(self):
        with self.assertRaisesRegex(ValueError, "insufficient operands"):
            eval_rpn(["2", "+"])

    def test_extra_operands(self):
        with self.assertRaisesRegex(ValueError, "extra operands"):
            eval_rpn(["2", "3", "4", "+"])

    def test_empty_input(self):
        with self.assertRaisesRegex(ValueError, "empty input"):
            eval_rpn([])

    def test_division_by_zero(self):
        with self.assertRaisesRegex(ValueError, "division by zero"):
            eval_rpn(["5", "0", "/"])

    def test_complex_expression(self):
        self.assertEqual(eval_rpn(["2", "1", "+", "3", "*"]), 9)


if __name__ == "__main__":
    unittest.main()
```

Notes:
- Integer division is defined as truncation toward zero, using `int(a / b)`.
- Negative numbers are accepted as integer tokens, e.g. `"-4"`.
- Invalid expressions raise `ValueError` with specific messages.

