    "I": 1,
    "V": 5,
    "X": 10,
    "L": 50,
    "C": 100,
    "D": 500,
    "M": 1000,
}

VALID_SUBTRACTIVES = {
    "IV", "IX",
    "XL", "XC",
    "CD", "CM",
}

CAN_REPEAT = {"I", "X", "C", "M"}
NON_REPEATABLE = {"V", "L", "D"}


def roman_to_int(s: str) -> int:
    if not isinstance(s, str):
        raise TypeError("Roman numeral must be a string")

    s = s.strip()
    if not s:
        raise ValueError("Roman numeral cannot be empty")

    if not re.fullmatch(r"[IVXLCDMivxlcdm]+", s):
        raise ValueError("Roman numeral contains invalid characters")

    s = s.upper()

    total = 0
    i = 0
    repeat_count = 1
    last_char = ""

    while i < len(s):
        ch = s[i]

        if ch == last_char:
            repeat_count += 1
        else:
            repeat_count = 1
            last_char = ch

        if ch in NON_REPEATABLE and repeat_count > 1:
            raise ValueError(f"Symbol {ch} cannot repeat")

        if ch in CAN_REPEAT and repeat_count > 3:
            raise ValueError(f"Symbol {ch} cannot repeat more than 3 times")

        if i + 1 < len(s):
            next_ch = s[i + 1]
            curr_val = ROMAN_VALUES[ch]
            next_val = ROMAN_VALUES[next_ch]

            if curr_val < next_val:
                pair = ch + next_ch

                if pair not in VALID_SUBTRACTIVES:
                    raise ValueError(f"Invalid subtractive pair: {pair}")

                if repeat_count > 1:
                    raise ValueError(f"Invalid repetition before subtractive pair: {pair}")

                total += next_val - curr_val
                i += 2
                last_char = ""
                repeat_count = 1
                continue

        total += ROMAN_VALUES[ch]
        i += 1

    canonical = int_to_roman(total)
    if s != canonical:
        raise ValueError("Malformed Roman numeral")

    return total


def int_to_roman(n: int) -> str:
    if not (1 <= n <= 3999):
        raise ValueError("Value out of supported Roman numeral range")

    parts = [
        (1000, "M"),
        (900, "CM"),
        (500, "D"),
        (400, "CD"),
        (100, "C"),
        (90, "XC"),
        (50, "L"),
        (40, "XL"),
        (10, "X"),
        (9, "IX"),
        (5, "V"),
        (4, "IV"),
        (1, "I"),
    ]

    result = []
    for value, symbol in parts:
        while n >= value:
            result.append(symbol)
            n -= value
    return "".join(result)


