```javascript
function longestSharedPrefix(strings) {
  if (!Array.isArray(strings) || strings.length === 0) return "";
  if (strings.length === 1) return String(strings[0] ?? "");

  const normalized = strings.map(s => String(s ?? ""));
  let prefix = normalized[0];

  for (let i = 1; i < normalized.length; i++) {
    const current = normalized[i];
    let j = 0;
    const max = Math.min(prefix.length, current.length);

    while (j < max && prefix[j] === current[j]) {
      j++;
    }

    prefix = prefix.slice(0, j);
    if (prefix === "") return "";
  }

  return prefix;
}
