**JSON serialization** is converting an in-memory value/object into a JSON string.

- JavaScript example: `JSON.stringify(value)`
- Use it when sending data over HTTP, saving to disk, or logging structured data.

Example:
```js
const user = { name: "Ada", age: 30 };
const json = JSON.stringify(user);
// '{"name":"Ada","age":30}'
```

**JSON parsing** is the reverse: converting a JSON string into an in-memory value/object.

- JavaScript example: `JSON.parse(jsonString)`
- Use it when reading API responses, config files, or stored data.

Example:
```js
const json = '{"name":"Ada","age":30}';
const user = JSON.parse(json);
// { name: "Ada", age: 30 }
```

### Important distinction
JSON is **text**, not a native object.

- Serialized JSON: `'{"x":1}'`
- Parsed object: `{ x: 1 }`

### Common parsing failures
Invalid JSON causes parsing errors, for example:

- Missing quotes around keys: `{name:"Ada"}`
- Trailing commas: `{"name":"Ada",}`
- Single quotes instead of double quotes: `{'name':'Ada'}`

---

## Safe pretty-print function

```js
function prettyPrintJson(input) {
  if (typeof input !== "string") {
    return {
      ok: false,
      error: "Input must be a JSON string."
    };
  }

  try {
    const parsed = JSON.parse(input);
    return {
      ok: true,
      value: JSON.stringify(parsed, null, 2)
    };
  } catch (error) {
    return {
      ok: false,
      error: "Invalid JSON input."
    };
  }
}
```

### Example usage

```js
console.log(prettyPrintJson('{"name":"Ada","skills":["math","programming"]}'));
/*
{
  ok: true,
  value: '{\n  "name": "Ada",\n  "skills": [\n    "math",\n    "programming"\n  ]\n}'
}
*/

console.log(prettyPrintJson('{"name":"Ada",}'));
/*
{
  ok: false,
  error: 'Invalid JSON input.'
}
*/
```

## Version that throws no surprises and includes parse details

```js
function prettyPrintJsonSafe(input, indent = 2) {
  if (typeof input !== "string") {
    return {
      ok: false,
      error: "Input must be a string."
    };
  }

  if (!Number.isInteger(indent) || indent < 0) {
    return {
      ok: false,
      error: "Indent must be a non-negative integer."
    };
  }

  try {
    const parsed = JSON.parse(input);
    return {
      ok: true,
      value: JSON.stringify(parsed, null, indent)
    };
  } catch (error) {
    return {
      ok: false,
      error: error instanceof Error ? error.message : "Invalid JSON input."
    };
  }
}
```

### Example
```js
const result = prettyPrintJsonSafe('{"a":1,"b":{"c":2}}', 4);

if (result.ok) {
  console.log(result.value);
} else {
  console.error(result.error);
}
```

