function transformRecords(input) {
  const allowedStatuses = new Set(["pending", "active", "disabled"]);
  const seenIds = new Set();

  const output = input.map((item, index) => {
    const { id, name, price, status } = item;

    if (seenIds.has(id)) {
      throw new Error(`Duplicate id at index ${index}: ${id}`);
    }
    seenIds.add(id);

    if (!allowedStatuses.has(status)) {
      throw new Error(`Invalid status at index ${index}: ${status}`);
    }

    const numericPrice = Number(price);
    if (!Number.isFinite(numericPrice)) {
      throw new Error(`Invalid price at index ${index}: ${price}`);
    }

    return {
      id,
      name,
      price: numericPrice.toFixed(2),
      status,
    };
  });

  return output.sort((a, b) => a.name.localeCompare(b.name));
}
```

