## More reusable generic version

If you want a reusable in-memory repository for any entity with an `id`:

```python
from __future__ import annotations

from abc import ABC, abstractmethod
from dataclasses import dataclass
from typing import Dict, Generic, List, Optional, Protocol, TypeVar


ID = TypeVar("ID")


class HasId(Protocol[ID]):
    id: ID


T = TypeVar("T", bound=HasId)


class Repository(ABC, Generic[T, ID]):
    @abstractmethod
    def add(self, entity: T) -> None:
        pass

    @abstractmethod
    def get_by_id(self, entity_id: ID) -> Optional[T]:
        pass

    @abstractmethod
    def list_all(self) -> List[T]:
        pass


class InMemoryRepository(Repository[T, ID], Generic[T, ID]):
    def __init__(self) -> None:
        self._items: Dict[ID, T] = {}

    def add(self, entity: T) -> None:
        self._items[entity.id] = entity

    def get_by_id(self, entity_id: ID) -> Optional[T]:
        return self._items.get(entity_id)

    def list_all(self) -> List[T]:
        return list(self._items.values())


@dataclass(frozen=True)
class Product:
    id: int
    name: str


repo = InMemoryRepository[Product, int]()
repo.add(Product(id=1, name="Keyboard"))
repo.add(Product(id=2, name="Mouse"))

print(repo.get_by_id(2))
print(repo.list_all())
```

