```js
function normalizeUsername(username) {
  return username
    .normalize('NFKC')
    .toLocaleLowerCase('en-US')
    .replace(/\p{White_Space}+/gu, '');
}

function validateUsername(candidate, existingUsernames = []) {
  const canonical = normalizeUsername(candidate);

  if (!canonical) {
    return { valid: false, reason: 'Username cannot be empty after normalization.' };
  }

  for (const existing of existingUsernames) {
    if (normalizeUsername(existing) === canonical) {
      return {
        valid: false,
        reason: `Username collides with existing username "${existing}" after normalization.`,
        canonical,
      };
    }
  }

  return { valid: true, canonical };
}
```

