```js
function slugify(input) {
  if (input == null) return "n-a";

  const text = String(input).trim();

  // Exact degenerate behavior:
  // - empty string -> "n-a"
  // - whitespace-only string -> "n-a"
  // - emoji-only string -> "n-a"
  // - combining-marks-only string -> "n-a"
  if (!text) return "n-a";

  const stripped = text
    .normalize("NFKD")
    // Remove combining marks
    .replace(/[\u0300-\u036f]/g, "")
    // Remove everything except letters, numbers, spaces, underscores, hyphens
    .replace(/[^\p{Letter}\p{Number}\s_-]+/gu, "")
    .trim()
    .toLowerCase();

  if (!stripped) return "n-a";

  return stripped
    .replace(/[\s_-]+/g, "-")
    .replace(/^-+|-+$/g, "") || "n-a";
}
```

### Exact outputs for degenerate inputs

| Input | Output |
|---|---|
| `""` | `"n-a"` |
| `"   \t\n"` | `"n-a"` |
| `"😀"` | `"n-a"` |
| `"🔥🎉🚀"` | `"n-a"` |
| `"\u0301"` | `"n-a"` |
| `"\u0301\u0327"` | `"n-a"` |

### Examples

```js
slugify("Hello World");          // "hello-world"
slugify("  Café au lait  ");     // "cafe-au-lait"
slugify("😀 Launch 🚀");         // "launch"
slugify("e\u0301lite");          // "elite"
slugify("");                     // "n-a"
slugify("   ");                  // "n-a"
slugify("🎉🔥");                 // "n-a"
slugify("\u0301\u0327");         // "n-a"
```

