Use a replacer that tracks first-seen object paths and emits a marker when the same object is encountered again.

```js
function stringifyCircular(value, space = 2) {
  const seen = new Map();

  return JSON.stringify(
    value,
    function (key, currentValue) {
      if (key === '') {
        seen.set(currentValue, '$');
        return currentValue;
      }

      if (currentValue && typeof currentValue === 'object') {
        const parentPath = seen.get(this);
        const path =
          Array.isArray(this)
            ? `${parentPath}[${key}]`
            : /^[A-Za-z_$][A-Za-z0-9_$]*$/.test(key)
              ? `${parentPath}.${key}`
              : `${parentPath}[${JSON.stringify(key)}]`;

        if (seen.has(currentValue)) {
          return { $ref: seen.get(currentValue) };
        }

        seen.set(currentValue, path);
      }

      return currentValue;
    },
    space
  );
}
```

Example:

```js
const a = { name: 'root' };
const b = { parent: a };
a.child = b;
a.self = a;

console.log(stringifyCircular(a));
```

Output:

```json
{
  "name": "root",
  "child": {
    "parent": {
      "$ref": "$"
    }
  },
  "self": {
    "$ref": "$"
  }
}
```

