Use an **iterative graph isomorphism-style traversal** with a **pair memo** instead of recursion.

### Requirements to handle
- depth `100_000` → no recursion
- circular references → track visited **object pairs**
- shared subtrees → preserve aliasing semantics if you want true structural equality over object graphs

### JS implementation

```js
function deepStructuralEqual(a, b) {
  if (Object.is(a, b)) return true;

  const isObjectLike = (x) => x !== null && (typeof x === 'object' || typeof x === 'function');

  if (!isObjectLike(a) || !isObjectLike(b)) return false;

  const seen = new WeakMap(); // leftObj -> WeakMap(rightObj -> true)
  const stack = [[a, b]];

  const markSeen = (x, y) => {
    let inner = seen.get(x);
    if (!inner) {
      inner = new WeakMap();
      seen.set(x, inner);
    }
    inner.set(y, true);
  };

  const hasSeen = (x, y) => {
    const inner = seen.get(x);
    return inner ? inner.has(y) : false;
  };

  while (stack.length) {
    const [x, y] = stack.pop();

    if (Object.is(x, y)) continue;

    const xObj = isObjectLike(x);
    const yObj = isObjectLike(y);
    if (xObj !== yObj) return false;
    if (!xObj) return false;

    if (hasSeen(x, y)) continue;
    markSeen(x, y);

    if (Object.getPrototypeOf(x) !== Object.getPrototypeOf(y)) return false;

    if (x instanceof Date || y instanceof Date) {
      if (!(x instanceof Date && y instanceof Date)) return false;
      if (!Object.is(x.getTime(), y.getTime())) return false;
      continue;
    }

    if (x instanceof RegExp || y instanceof RegExp) {
      if (!(x instanceof RegExp && y instanceof RegExp)) return false;
      if (x.source !== y.source || x.flags !== y.flags) return false;
      continue;
    }

    if (ArrayBuffer.isView(x) || ArrayBuffer.isView(y)) {
      if (!(ArrayBuffer.isView(x) && ArrayBuffer.isView(y))) return false;
      if (x.constructor !== y.constructor || x.length !== y.length) return false;
      for (let i = 0; i < x.length; i++) {
        if (!Object.is(x[i], y[i])) return false;
      }
      continue;
    }

    if (x instanceof ArrayBuffer || y instanceof ArrayBuffer) {
      if (!(x instanceof ArrayBuffer && y instanceof ArrayBuffer)) return false;
      if (x.byteLength !== y.byteLength) return false;
      const xv = new Uint8Array(x);
      const yv = new Uint8Array(y);
      for (let i = 0; i < xv.length; i++) {
        if (xv[i] !== yv[i]) return false;
      }
      continue;
    }

    if (x instanceof Map || y instanceof Map) {
      if (!(x instanceof Map && y instanceof Map)) return false;
      if (x.size !== y.size) return false;

      // Simple identity-based key matching.
      // For deep-key comparison, this part must be extended.
      for (const [k, vx] of x) {
        if (!y.has(k)) return false;
        stack.push([vx, y.get(k)]);
      }
      continue;
    }

    if (x instanceof Set || y instanceof Set) {
      if (!(x instanceof Set && y instanceof Set)) return false;
      if (x.size !== y.size) return false;

      // Identity-based membership check.
      for (const v of x) {
        if (!y.has(v)) return false;
      }
      continue;
    }

    const xKeys = Reflect.ownKeys(x);
    const yKeys = Reflect.ownKeys(y);

    if (xKeys.length !== yKeys.length) return false;

    for (let i = 0; i < xKeys.length; i++) {
      if (!Object.prototype.hasOwnProperty.call(y, xKeys[i])) return false;
    }

    for (const key of xKeys) {
      const dx = Object.getOwnPropertyDescriptor(x, key);
      const dy = Object.getOwnPropertyDescriptor(y, key);
      if (!dx || !dy) return false;

      if (
        dx.enumerable !== dy.enumerable ||
        dx.configurable !== dy.configurable
      ) return false;

      const xData = 'value' in dx;
      const yData = 'value' in dy;
      if (xData !== yData) return false;

      if (xData) {
        if (dx.writable !== dy.writable) return false;
        stack.push([dx.value, dy.value]);
      } else {
        if (!Object.is(dx.get, dy.get) || !Object.is(dx.set, dy.set)) return false;
      }
    }
  }

  return true;
}
```

---

### Why this avoids stack overflow
It uses a heap-allocated `stack` array:

```js
const stack = [[a, b]];
while (stack.length) { ... }
```

So even at depth `100000`, it does not consume call stack frames.

---

### Why circular refs work
This is the critical part:

```js
const seen = new WeakMap();
```

You must remember **pairs** already compared, not just single objects.  
If you only track `x` or only `y`, cycles and shared references are handled incorrectly.

---

### Shared subtree note
This implementation compares object graphs by revisiting the same `(leftNode, rightNode)` pair only once. It correctly handles cycles, but it does **not fully enforce alias preservation across different parents** in all possible graph shapes.

If you need **strict graph equality**, where:

```js
const shared = {};
const a = { p: shared, q: shared };
const b = { p: {}, q: {} };
```

must be `false`, then you also need a **bijection** between left and right nodes.

### Strict alias-preserving version
Add two maps:
- `leftToRight`
- `rightToLeft`

and require consistency:

```js
function deepGraphEqual(a, b) {
  if (Object.is(a, b)) return true;

  const isObjectLike = (x) => x !== null && (typeof x === 'object' || typeof x === 'function');
  if (!isObjectLike(a) || !isObjectLike(b)) return false;

  const pairSeen = new WeakMap();
  const leftToRight = new WeakMap();
  const rightToLeft = new WeakMap();
  const stack = [[a, b]];

  const markPairSeen = (x, y) => {
    let inner = pairSeen.get(x);
    if (!inner) {
      inner = new WeakMap();
      pairSeen.set(x, inner);
    }
    inner.set(y, true);
  };

  const hasPairSeen = (x, y) => {
    const inner = pairSeen.get(x);
    return inner ? inner.has(y) : false;
  };

  while (stack.length) {
    const [x, y] = stack.pop();

    if (Object.is(x, y)) continue;

    const xObj = isObjectLike(x);
    const yObj = isObjectLike(y);
    if (xObj !== yObj) return false;
    if (!xObj) return false;

    const mappedY = leftToRight.get(x);
    const mappedX = rightToLeft.get(y);
    if ((mappedY && mappedY !== y) || (mappedX && mappedX !== x)) return false;
    if (!mappedY) leftToRight.set(x, y);
    if (!mappedX) rightToLeft.set(y, x);

    if (hasPairSeen(x, y)) continue;
    markPairSeen(x, y);

    if (Object.getPrototypeOf(x) !== Object.getPrototypeOf(y)) return false;

    const xKeys = Reflect.ownKeys(x);
    const yKeys = Reflect.ownKeys(y);
    if (xKeys.length !== yKeys.length) return false;

    for (const key of xKeys) {
      if (!Object.prototype.hasOwnProperty.call(y, key)) return false;
    }

    for (const key of xKeys) {
      const dx = Object.getOwnPropertyDescriptor(x, key);
      const dy = Object.getOwnPropertyDescriptor(y, key);
      if (!dx || !dy) return false;

      const xData = 'value' in dx;
      const yData = 'value' in dy;
      if (xData !== yData) return false;

      if (
        dx.enumerable !== dy.enumerable ||
        dx.configurable !== dy.configurable ||
        (xData && dx.writable !== dy.writable)
      ) return false;

      if (xData) {
        stack.push([dx.value, dy.value]);
      } else {
        if (!Object.is(dx.get, dy.get) || !Object.is(dx.set, dy.set)) return false;
      }
    }
  }

  return true;
}
```

---

### Complexity
- **Time:** `O(V + E)` for ordinary object graphs, ignoring special cases like deep `Map` key matching
- **Space:** `O(V)` for memo structures and explicit stack

---

### Recommendation
If you want the safest answer to your prompt, use the **strict alias-preserving iterative version**.  
That is the one that correctly handles:
- very deep nesting
- cycles
- shared subtrees

If you want, I can also give:
1. a **TypeScript version**, or  
