Use a reversible path encoding: treat `.` as a path separator, and escape literal dots and backslashes inside keys with backslash.

### Rules
- Join nested keys with `.`
- Escape key characters:
  - `\` → `\\`
  - `.` → `\.`
- Preserve container leaves:
  - empty object `{}` stays as a value
  - empty array `[]` stays as a value
- Non-empty arrays:
  - either keep whole arrays as leaf values, or flatten indices too
  - if flattening indices, numeric segments are just normal path parts

### Example
Input:
```json
{
  "a": {
    "b.c": {
      "d": 1
    },
    "emptyObj": {},
    "emptyArr": []
  },
  "x.y": 2
}
```

Output:
```json
{
  "a.b\\.c.d": 1,
  "a.emptyObj": {},
  "a.emptyArr": [],
  "x\\.y": 2
}
```

### JavaScript implementation
```js
function flattenObject(input) {
  const out = {};

  const escapeKey = (key) => key.replace(/\\/g, "\\\\").replace(/\./g, "\\.");

  function visit(value, path) {
    if (Array.isArray(value)) {
      if (value.length === 0) {
        out[path] = [];
        return;
      }

      for (let i = 0; i < value.length; i++) {
        const nextPath = path ? `${path}.${i}` : String(i);
        visit(value[i], nextPath);
      }
      return;
    }

    if (value && typeof value === "object") {
      const keys = Object.keys(value);

      if (keys.length === 0) {
        out[path] = {};
        return;
      }

      for (const key of keys) {
        const escaped = escapeKey(key);
        const nextPath = path ? `${path}.${escaped}` : escaped;
        visit(value[key], nextPath);
      }
      return;
    }

    out[path] = value;
  }

  if (input && typeof input === "object" && !Array.isArray(input)) {
    const keys = Object.keys(input);

    if (keys.length === 0) {
      return { "": {} };
    }

    for (const key of keys) {
      visit(input[key], escapeKey(key));
    }

    return out;
  }

  return { "": input };
}
```

### Unflattening
To reverse it, split on dots that are **not escaped**, then unescape:
- `\\` → `\`
- `\.` → `.`

A safe splitter scans character by character instead of using `split('.')`.

If you want, I can also give you the matching `unflattenObject` implementation.

812.answer:
```js
function unflatten(input) {
  const result = {};

  for (const [path, value] of Object.entries(input)) {
    const keys = path.split(".");
    let current = result;

    for (let i = 0; i < keys.length; i++) {
      const key = keys[i];
      const isLeaf = i === keys.length - 1;

      if (isLeaf) {
        if (
          Object.prototype.hasOwnProperty.call(current, key) &&
          current[key] !== undefined
        ) {
          throw new Error(`Conflict at "${path}"`);
        }
        current[key] = value;
        continue;
      }

      if (Object.prototype.hasOwnProperty.call(current, key)) {
        if (
          current[key] === null ||
          typeof current[key] !== "object" ||
          Array.isArray(current[key])
        ) {
          throw new Error(`Conflict at "${path}"`);
        }
      } else {
        current[key] = {};
      }

      current = current[key];
    }
  }

  for (const path of Object.keys(input)) {
    const keys = path.split(".");
    let current = result;

    for (let i = 0; i < keys.length; i++) {
      current = current[keys[i]];
      if (i < keys.length - 1) {
        const prefix = keys.slice(0, i + 1).join(".");
        if (Object.prototype.hasOwnProperty.call(input, prefix)) {
          throw new Error(`Conflict between "${prefix}" and "${path}"`);
        }
      }
    }
  }

  return result;
}
```

Example:

```js
unflatten({
  "a.b": 1,
  "a.c": 2,
  d: 3
});
// { a: { b: 1, c: 2 }, d: 3 }

unflatten({
  a: 1,
  "a.b": 2
});
// throws Error: Conflict between "a" and "a.b"
```

