const INT64_MAX = 9223372036854775807n;

function parseSafeInt64(input) {
  if (typeof input !== 'string') {
    throw new TypeError('Expected a string');
  }

  if (!/^(0|[1-9][0-9]*)$/.test(input)) {
    throw new Error('Invalid decimal integer string');
  }

