- or a **faster chunked implementation** for 100k-digit inputs.

816.answer:
Use string-based modular arithmetic.

If you want to compute something like:

- `a + b`
- `a - b`
- `a * b`
- `a % m`
- `pow(a, b, m)`

for decimal strings up to 10,000 digits, you must avoid parsing into native numbers and instead operate digit-by-digit.

## Most likely needed: modular exponentiation on huge decimal strings

If the task is to compute:

```text
(a^b) mod m
```

where `a`, `b`, and `m` are decimal strings, here is a safe approach:

1. Reduce `a mod m` using decimal-string division logic.
2. Process exponent `b` as a decimal string.
3. Repeatedly:
   - if `b` is odd, multiply result by base modulo `m`
   - square base modulo `m`
   - divide `b` by 2 as a decimal string

This never requires native integer conversion of the full values.

---

## JavaScript implementation

```js
function stripLeadingZeros(s) {
  s = s.replace(/^0+/, "");
  return s === "" ? "0" : s;
}

function compareStrings(a, b) {
  a = stripLeadingZeros(a);
  b = stripLeadingZeros(b);
  if (a.length !== b.length) return a.length < b.length ? -1 : 1;
  if (a === b) return 0;
  return a < b ? -1 : 1;
}

function subtractStrings(a, b) {
  // assumes a >= b, both nonnegative integer strings
  a = a.split("").map(Number);
  b = b.split("").map(Number);
  let i = a.length - 1;
  let j = b.length - 1;
  let borrow = 0;
  let out = [];

  while (i >= 0 || j >= 0) {
    let x = i >= 0 ? a[i] : 0;
    let y = j >= 0 ? b[j] : 0;
    x -= borrow;
    if (x < y) {
      x += 10;
      borrow = 1;
    } else {
      borrow = 0;
    }
    out.push(x - y);
    i--;
    j--;
  }

  while (out.length > 1 && out[out.length - 1] === 0) out.pop();
  return out.reverse().join("");
}

function addStrings(a, b) {
  let i = a.length - 1;
  let j = b.length - 1;
  let carry = 0;
  let out = [];

  while (i >= 0 || j >= 0 || carry) {
    const x = i >= 0 ? a.charCodeAt(i) - 48 : 0;
    const y = j >= 0 ? b.charCodeAt(j) - 48 : 0;
    const sum = x + y + carry;
    out.push(String(sum % 10));
    carry = Math.floor(sum / 10);
    i--;
    j--;
  }

  return out.reverse().join("");
}

function multiplyStringsSmall(a, digit) {
  digit = Number(digit);
  if (digit === 0 || a === "0") return "0";
  if (digit === 1) return a;

  let carry = 0;
  let out = [];
  for (let i = a.length - 1; i >= 0; i--) {
    const prod = (a.charCodeAt(i) - 48) * digit + carry;
    out.push(String(prod % 10));
    carry = Math.floor(prod / 10);
  }
  while (carry) {
    out.push(String(carry % 10));
    carry = Math.floor(carry / 10);
  }
  return out.reverse().join("");
}

function modString(num, mod) {
  mod = stripLeadingZeros(mod);
  if (mod === "1") return "0";

  let rem = "0";
  for (const ch of num) {
    rem = addStrings(multiplyStringsSmall(rem, 10), ch);
    while (compareStrings(rem, mod) >= 0) {
      rem = subtractStrings(rem, mod);
    }
  }
  return stripLeadingZeros(rem);
}

function multiplyMod(a, b, mod) {
  a = modString(a, mod);
  b = stripLeadingZeros(b);
  let result = "0";

  for (let i = b.length - 1; i >= 0; i--) {
    const digit = b.charCodeAt(i) - 48;
    let term = "0";
    let cur = a;

    let d = digit;
    while (d > 0) {
      if (d & 1) term = modString(addStrings(term, cur), mod);
      cur = modString(addStrings(cur, cur), mod);
      d >>= 1;
    }

    for (let z = 0; z < b.length - 1 - i; z++) {
      term = modString(multiplyStringsSmall(term, 10), mod);
    }

    result = modString(addStrings(result, term), mod);
  }

  return result;
}

function div2String(s) {
  let carry = 0;
  let out = "";
  for (const ch of s) {
    const cur = carry * 10 + (ch.charCodeAt(0) - 48);
    out += String(Math.floor(cur / 2));
    carry = cur % 2;
  }
  return stripLeadingZeros(out);
}

function isOddString(s) {
  return ((s.charCodeAt(s.length - 1) - 48) & 1) === 1;
}

function powModHuge(a, b, mod) {
  mod = stripLeadingZeros(mod);
  if (mod === "0") throw new Error("modulus must be nonzero");
  if (mod === "1") return "0";

  let base = modString(stripLeadingZeros(a), mod);
  let exp = stripLeadingZeros(b);
  let result = "1";

  while (exp !== "0") {
    if (isOddString(exp)) {
      result = multiplyMod(result, base, mod);
    }
    base = multiplyMod(base, base, mod);
    exp = div2String(exp);
  }

  return stripLeadingZeros(result);
}
```

---

## Example

```js
console.log(powModHuge(
  "123456789123456789123456789",
  "987654321987654321987654321",
  "1000000007"
));
```

---

## Important note

The `modString` implementation above uses repeated subtraction for quotient selection, which is correct but slow for very large moduli.

For 10,000-digit inputs, a faster implementation should use:

- long division for `num % mod`
- schoolbook or Karatsuba multiplication on strings
