  const y = parse(b);

  const scale = Math.max(x.frac.length, y.frac.length);
  const fracA = x.frac.padEnd(scale, "0");
  const fracB = y.frac.padEnd(scale, "0");

  let carry = 0;
  let fracSum = "";

  for (let i = scale - 1; i >= 0; i--) {
    const sum = (fracA.charCodeAt(i) - 48) + (fracB.charCodeAt(i) - 48) + carry;
    fracSum = String(sum % 10) + fracSum;
    carry = Math.floor(sum / 10);
  }

  const wholeA = x.whole;
  const wholeB = y.whole;
  let i = wholeA.length - 1;
  let j = wholeB.length - 1;
  let wholeSum = "";

  while (i >= 0 || j >= 0 || carry) {
    const da = i >= 0 ? wholeA.charCodeAt(i) - 48 : 0;
    const db = j >= 0 ? wholeB.charCodeAt(j) - 48 : 0;
    const sum = da + db + carry;
    wholeSum = String(sum % 10) + wholeSum;
    carry = Math.floor(sum / 10);
    i--;
    j--;
  }

  if (scale === 0) return wholeSum;

  fracSum = fracSum.replace(/0+$/, "");
