```js
function roundBankers(value, places = 0) {
  const s = String(value).trim();
  if (!/^[-+]?\d+(\.\d+)?$/.test(s)) throw new Error("Invalid decimal string");

  const negative = s.startsWith("-");
  const unsigned = s.replace(/^[-+]/, "");
  const [intPart, fracPart = ""] = unsigned.split(".");

  if (places === 0) {
    const digits = intPart + fracPart;
    return applyHalfEven(intPart, fracPart, 0, negative);
  }

  return applyHalfEven(intPart, fracPart, places, negative);
}

function applyHalfEven(intPart, fracPart, places, negative) {
  const frac = fracPart.padEnd(places + 1, "0");
  const keepFrac = frac.slice(0, places);
  const roundDigit = frac[places] || "0";
  const rest = fracPart.slice(places + 1);

  let carry = false;

  if (roundDigit > "5") {
    carry = true;
  } else if (roundDigit < "5") {
    carry = false;
  } else {
    const hasMoreNonZero = /[1-9]/.test(rest);
    if (hasMoreNonZero) {
      carry = true;
    } else {
      const lastKeptDigit =
        places > 0
          ? (keepFrac[keepFrac.length - 1] || "0")
          : intPart[intPart.length - 1];
      carry = Number(lastKeptDigit) % 2 === 1;
    }
  }

  let whole = intPart;
  let fraction = keepFrac;

  if (carry) {
    if (places > 0) {
      let digits = (whole + fraction).split("");
      let i = digits.length - 1;
      while (i >= 0) {
        if (digits[i] === "9") {
          digits[i] = "0";
          i--;
        } else {
          digits[i] = String(Number(digits[i]) + 1);
          break;
        }
      }
      if (i < 0) digits.unshift("1");
      whole = digits.slice(0, digits.length - places).join("") || "0";
      fraction = digits.slice(digits.length - places).join("").padStart(places, "0");
    } else {
      whole = addOne(intPart);
    }
  }

  const sign = negative && (whole !== "0" || /[1-9]/.test(fraction)) ? "-" : "";
  return places > 0 ? `${sign}${whole}.${fraction}` : `${sign}${whole}`;
}

function addOne(numStr) {
  const digits = numStr.split("");
  let i = digits.length - 1;
  while (i >= 0) {
    if (digits[i] === "9") {
      digits[i] = "0";
      i--;
    } else {
      digits[i] = String(Number(digits[i]) + 1);
      return digits.join("");
    }
  }
  digits.unshift("1");
  return digits.join("");
}
```

