function evaluateRule(left, op, right, tolerance = DEFAULT_EPSILON) {
  switch (op) {
    case '==':
      return nearlyEqual(left, right, tolerance);
    case '!=':
      return !nearlyEqual(left, right, tolerance);
    case '<=':
      return left < right || nearlyEqual(left, right, tolerance);
    case '>=':
      return left > right || nearlyEqual(left, right, tolerance);
    case '<':
      return left < right && !nearlyEqual(left, right, tolerance);
    case '>':
      return left > right && !nearlyEqual(left, right, tolerance);
    default:
      throw new Error(`Unsupported operator: ${op}`);
  }
}
