  const dateA = getLocalDateParts(a, timeZone);
  const dateB = getLocalDateParts(b, timeZone);
  return daysFromCivil(dateA.year, dateA.month, dateA.day) -
         daysFromCivil(dateB.year, dateB.month, dateB.day);
