function normalizeMinutes(value) {
  if (typeof value === 'number') return value;
  const [h, m] = value.split(':').map(Number);
  return h * 60 + m;
}

function expandInterval(interval) {
  const start = normalizeMinutes(interval.start);
  const end = normalizeMinutes(interval.end);
  const wraps = end < start;

  if (wraps) {
    return [
      { start, end: 1440, startInclusive: interval.startInclusive, endInclusive: false },
      { start: 0, end, startInclusive: false, endInclusive: interval.endInclusive },
    ];
  }

  return [
    {
      start,
      end,
      startInclusive: interval.startInclusive,
      endInclusive: interval.endInclusive,
    },
  ];
}

function segmentsOverlap(a, b) {
  const left = Math.max(a.start, b.start);
  const right = Math.min(a.end, b.end);

  if (left < right) return true;
  if (left > right) return false;

  const aIncludes =
    (a.start === left && a.startInclusive) || (a.end === left && a.endInclusive);
  const bIncludes =
    (b.start === left && b.startInclusive) || (b.end === left && b.endInclusive);

  return aIncludes && bIncludes;
}

function intervalsOverlap(a, b) {
  const aSegments = expandInterval(a);
  const bSegments = expandInterval(b);

  for (const aSeg of aSegments) {
    for (const bSeg of bSegments) {
      if (segmentsOverlap(aSeg, bSeg)) return true;
    }
  }

  return false;
}
