```ts
type PaginationResult<T> = {
  items: T[];
  page: number;
  pageSize: number;
  totalItems: bigint;
  totalPages: bigint;
  hasPreviousPage: boolean;
  hasNextPage: boolean;
  isValid: boolean;
  error: "INVALID_PAGE_SIZE" | "INVALID_PAGE_NUMBER" | null;
};

function paginate<T>(
  items: readonly T[],
  page: number,
  pageSize: number
): PaginationResult<T> {
  const totalItems = BigInt(items.length);

  if (pageSize <= 0) {
    return {
      items: [],
      page,
      pageSize,
      totalItems,
      totalPages: 0n,
      hasPreviousPage: false,
      hasNextPage: false,
      isValid: false,
      error: "INVALID_PAGE_SIZE",
    };
  }

  if (page < 1) {
    return {
      items: [],
      page,
      pageSize,
      totalItems,
      totalPages: totalItems === 0n ? 0n : (totalItems + BigInt(pageSize) - 1n) / BigInt(pageSize),
      hasPreviousPage: false,
      hasNextPage: false,
      isValid: false,
      error: "INVALID_PAGE_NUMBER",
    };
  }

  const size = BigInt(pageSize);
  const totalPages = totalItems === 0n ? 0n : (totalItems + size - 1n) / size;

  if (totalItems === 0n) {
    return {
      items: [],
      page,
      pageSize,
      totalItems,
      totalPages,
      hasPreviousPage: false,
      hasNextPage: false,
      isValid: true,
      error: null,
    };
  }

  const start = (page - 1) * pageSize;
  const pagedItems = start >= items.length ? [] : items.slice(start, start + pageSize);

  return {
    items: pagedItems,
    page,
    pageSize,
    totalItems,
    totalPages,
    hasPreviousPage: page > 1 && totalPages > 0n,
    hasNextPage: BigInt(page) < totalPages,
    isValid: true,
    error: null,
  };
}
```

### Exact invalid return values

#### 1. `pageSize <= 0`
Returns:
- `items: []`
- `totalPages: 0n`
- `hasPreviousPage: false`
- `hasNextPage: false`
- `isValid: false`
- `error: "INVALID_PAGE_SIZE"`

#### 2. `page < 1`
Returns:
- `items: []`
- `isValid: false`
- `error: "INVALID_PAGE_NUMBER"`
- `totalPages` still computed from the dataset if `pageSize > 0`

### Behavior notes
- **Empty dataset**: valid request, returns `items: []`, `totalItems: 0n`, `totalPages: 0n`.
- **Page beyond last page**: valid request, returns `items: []`.
- **Large totals**: `totalItems` and `totalPages` use `bigint`, so they are safe beyond 32-bit integer limits.

### Example
```ts
const data = [1, 2, 3, 4, 5];

console.log(paginate(data, 1, 2));
// items: [1, 2], totalItems: 5n, totalPages: 3n

console.log(paginate(data, -1, 2));
// invalid, error: "INVALID_PAGE_NUMBER"

console.log(paginate(data, 1, 0));
// invalid, error: "INVALID_PAGE_SIZE"

console.log(paginate([], 1, 10));
// valid, items: [], totalItems: 0n, totalPages: 0n
```

