```js
/**
 * Binary search that returns the first index whose value is equal to target
 * under JavaScript's SameValueZero comparison policy:
 * - NaN matches NaN
 * - 0 and -0 are treated as equal
 * - other values use === semantics
 *
 * Assumes the array is already sorted according to the same ordering used
 * to group equal values together.
 */
function binarySearchFirst(arr, target) {
  let left = 0;
  let right = arr.length - 1;
  let result = -1;

  while (left <= right) {
    const mid = left + ((right - left) >> 1);
    const value = arr[mid];

    if (sameValueZero(value, target)) {
      result = mid;
      right = mid - 1;
    } else if (compare(value, target) < 0) {
      left = mid + 1;
    } else {
      right = mid - 1;
    }
  }

  return result;
}

function sameValueZero(a, b) {
  return a === b || (Number.isNaN(a) && Number.isNaN(b));
}

function compare(a, b) {
  if (sameValueZero(a, b)) return 0;
  if (Number.isNaN(a)) return 1;
  if (Number.isNaN(b)) return -1;
  return a < b ? -1 : 1;
}

// Example:
console.log(binarySearchFirst([1, 2, 2, 2, 3], 2));     // 1
console.log(binarySearchFirst([-0, 0, 0, 1], 0));       // 0
console.log(binarySearchFirst([1, 2, 3, NaN, NaN], NaN)); // 3
console.log(binarySearchFirst([1, 2, 3], 4));           // -1
```

Policy:
- Equality uses **SameValueZero**
- Returned index is the **leftmost matching index**
- `NaN` is treated as equal to `NaN`
- `-0` and `0` are treated as equal

