function parseIPv6(input) {
  if (typeof input !== 'string') return null;

  const value = input.trim();
  if (!value) return null;

  if ((value.match(/::/g) || []).length > 1) return null;

  let head = '';
  let tail = '';
  const hasCompression = value.includes('::');

  if (hasCompression) {
    [head, tail] = value.split('::');
  } else {
    head = value;
  }

  const headParts = head ? head.split(':') : [];
  const tailParts = tail ? tail.split(':') : [];

  const parseIPv4 = (s) => {
    const parts = s.split('.');
    if (parts.length !== 4) return null;
    const nums = [];
    for (const part of parts) {
      if (!/^\d+$/.test(part)) return null;
      if (part.length > 1 && part[0] === '0') return null;
      const n = Number(part);
      if (n < 0 || n > 255) return null;
      nums.push(n);
    }
    return [(nums[0] << 8) | nums[1], (nums[2] << 8) | nums[3]];
  };

  const parseHextet = (s) => (/^[0-9a-fA-F]{1,4}$/.test(s) ? parseInt(s, 16) : null);

  const expandSide = (parts, allowIPv4) => {
    const out = [];
    for (let i = 0; i < parts.length; i++) {
      const part = parts[i];
      if (part === '') return null;

      if (part.includes('.')) {
        if (!allowIPv4 || i !== parts.length - 1) return null;
        const mapped = parseIPv4(part);
        if (!mapped) return null;
        out.push(...mapped);
      } else {
        const n = parseHextet(part);
        if (n == null) return null;
        out.push(n);
      }
    }
    return out;
  };

  const left = expandSide(headParts, true);
  const right = expandSide(tailParts, true);
  if (!left || !right) return null;

  let groups;
  if (hasCompression) {
    const missing = 8 - (left.length + right.length);
    if (missing < 1) return null;
    groups = [...left, ...Array(missing).fill(0), ...right];
  } else {
    groups = [...left];
    if (groups.length !== 8) return null;
  }

  if (groups.length !== 8) return null;
  if (groups.some((n) => !Number.isInteger(n) || n < 0 || n > 0xffff)) return null;

  return canonicalIPv6(groups);
}

function canonicalIPv6(groups) {
  const hex = groups.map((n) => n.toString(16));

  let bestStart = -1;
  let bestLen = 0;

  for (let i = 0; i < hex.length; ) {
    if (groups[i] !== 0) {
      i++;
      continue;
    }
    let j = i;
    while (j < groups.length && groups[j] === 0) j++;
    const len = j - i;
    if (len > 1 && len > bestLen) {
      bestStart = i;
      bestLen = len;
    }
    i = j;
  }

  if (bestStart === -1) return hex.join(':');

  const left = hex.slice(0, bestStart).join(':');
  const right = hex.slice(bestStart + bestLen).join(':');

  if (!left && !right) return '::';
  if (!left) return `::${right}`;
  if (!right) return `${left}::`;
  return `${left}::${right}`;
}

// Examples
const samples = [
  '2001:0DB8:0000:0000:0000:FF00:0042:8329',
  '2001:db8::ff00:42:8329',
  '::1',
  '::',
  '0:0:0:0:0:ffff:192.168.1.1',
  '2001:db8:::1',
  '1::2::3',
  'GGGG::1',
];

for (const s of samples) {
  console.log(s, '=>', parseIPv6(s));
}
```

