```js
function serializeFormData(input) {
  const pairs = [];

  const encode = (value) =>
    encodeURIComponent(String(value)).replace(/%20/g, "+");

  const escapeKeyPart = (part) =>
    String(part).replace(/\[/g, "%5B").replace(/\]/g, "%5D");

  const pushPair = (key, value) => {
    if (value === null) {
      pairs.push(`${key}=`);
      return;
    }

    if (typeof value === "boolean") {
      pairs.push(`${key}=${value ? "true" : "false"}`);
      return;
    }

    pairs.push(`${key}=${encode(value)}`);
  };

  const visit = (value, path) => {
    if (Array.isArray(value)) {
      for (const item of value) {
        visit(item, `${path}[]`);
      }
      return;
    }

    if (value && typeof value === "object") {
      for (const [rawKey, nestedValue] of Object.entries(value)) {
        const keyPart = escapeKeyPart(rawKey);
        const nextPath = path ? `${path}[${keyPart}]` : keyPart;
        visit(nestedValue, nextPath);
      }
      return;
    }

    pushPair(path, value ?? "");
  };

  for (const [rawKey, value] of Object.entries(input)) {
    visit(value, escapeKeyPart(rawKey));
  }

  return pairs.join("&");
}
```

### Behavior

```js
serializeFormData({
  name: "",
  active: false,
  age: null,
  tags: ["a", "b"],
  user: {
    email: "x@example.com",
    roles: ["admin", "editor"],
  },
  dup: ["x", "x"],
  "a[b]": "literal",
});
```

Returns:

```txt
name=&active=false&age=&tags[]=a&tags[]=b&user[email]=x%40example.com&user[roles][]=admin&user[roles][]=editor&dup[]=x&dup[]=x&a%5Bb%5D=literal
```

### Notes
- **Arrays** use `[]`
- **Empty strings** become `key=`
- **Nulls** become `key=`
- **Booleans** become `true` / `false`
- **Duplicate keys** are preserved by emitting repeated pairs
- **Literal brackets in keys** are escaped as `%5B` and `%5D`, so `"a[b]"` is treated as a literal key, not nesting

