```js
import { createHash } from 'node:crypto';

/**
 * Stable hash for arbitrary JSON-like data.
 * - Object key order is ignored
 * - Array order is preserved
 * - Circular/shared references are encoded deterministically
 */
export function stableJsonHash(value, algorithm = 'sha256') {
  const seen = new Map();
  let nextRefId = 0;

  const canonicalize = (node) => {
    if (node === null) return 'null';

    const t = typeof node;

    if (t === 'string') return `str:${JSON.stringify(node)}`;
    if (t === 'number') {
      if (Number.isNaN(node)) return 'num:NaN';
      if (node === Infinity) return 'num:Infinity';
      if (node === -Infinity) return 'num:-Infinity';
      return `num:${Object.is(node, -0) ? '-0' : String(node)}`;
    }
    if (t === 'boolean') return `bool:${node}`;
    if (t === 'bigint') return `big:${node}n`;
    if (t === 'undefined') return 'undef';
    if (t === 'symbol') throw new TypeError('Cannot hash symbol values');
    if (t === 'function') throw new TypeError('Cannot hash function values');

    if (seen.has(node)) {
      return `ref:${seen.get(node)}`;
    }

    const refId = nextRefId++;
    seen.set(node, refId);

    if (Array.isArray(node)) {
      const items = node.map(canonicalize);
      return `arr#${refId}[${items.join(',')}]`;
    }

    if (node instanceof Date) {
      return `date#${refId}:${JSON.stringify(node.toISOString())}`;
    }

    if (node instanceof RegExp) {
      return `re#${refId}:${JSON.stringify(node.toString())}`;
    }

    const proto = Object.getPrototypeOf(node);
    if (proto !== Object.prototype && proto !== null) {
      throw new TypeError('Only plain objects, arrays, and JSON-like values are supported');
    }

    const keys = Object.keys(node).sort();
    const parts = [];
    for (const key of keys) {
      parts.push(`${JSON.stringify(key)}:${canonicalize(node[key])}`);
    }
    return `obj#${refId}{${parts.join(',')}}`;
  };

  return createHash(algorithm).update(canonicalize(value)).digest('hex');
}
```

