```js
/**
 * Diff two JSON-like values and report precise path-based changes.
 *
 * Handles:
 * - additions / deletions
 * - primitive value changes
 * - type changes
 * - sparse arrays (distinguishes holes from explicit `undefined`)
 * - circular references
 *
 * Path format:
 * - object keys: $.user.name
 * - array indexes: $.items[2]
 *
 * Notes:
 * - "JSON-like" here includes JS objects/arrays/primitives/null, and may include
 *   undefined in sparse arrays or object properties.
 * - Circular references are detected per-side and compared structurally enough
 *   to avoid infinite recursion.
 */
function diffJsonLike(left, right) {
  const changes = [];
  const seen = new WeakMap();

  walk(left, right, '$');
  return changes;

  function walk(a, b, path) {
    if (Object.is(a, b)) return;

    const aTag = valueTag(a);
    const bTag = valueTag(b);

    if (aTag !== bTag) {
      changes.push({
        path,
        kind: 'type',
        leftType: aTag,
        rightType: bTag,
        left: a,
        right: b,
      });
      return;
    }

    if (a === null || b === null || typeof a !== 'object') {
      changes.push({
        path,
        kind: 'change',
        left: a,
        right: b,
      });
      return;
    }

    if (isCircularPair(a, b, path)) return;

    if (Array.isArray(a)) {
      diffArray(a, b, path);
      return;
    }

    diffObject(a, b, path);
  }

  function diffObject(a, b, path) {
    const keys = new Set([...Object.keys(a), ...Object.keys(b)]);

    for (const key of keys) {
      const aHas = Object.prototype.hasOwnProperty.call(a, key);
      const bHas = Object.prototype.hasOwnProperty.call(b, key);
      const nextPath = pathJoin(path, key);

      if (!aHas && bHas) {
        changes.push({
          path: nextPath,
          kind: 'add',
          right: b[key],
        });
        continue;
      }

      if (aHas && !bHas) {
        changes.push({
          path: nextPath,
          kind: 'delete',
          left: a[key],
        });
        continue;
      }

      walk(a[key], b[key], nextPath);
    }
  }

  function diffArray(a, b, path) {
    const max = Math.max(a.length, b.length);

    if (a.length !== b.length) {
      changes.push({
        path: path + '.length',
        kind: 'change',
        left: a.length,
        right: b.length,
      });
    }

    for (let i = 0; i < max; i++) {
      const aHas = i in a;
      const bHas = i in b;
      const nextPath = `${path}[${i}]`;

      if (!aHas && bHas) {
        changes.push({
          path: nextPath,
          kind: 'add',
          right: b[i],
          sparse: true,
        });
        continue;
      }

      if (aHas && !bHas) {
        changes.push({
          path: nextPath,
          kind: 'delete',
          left: a[i],
          sparse: true,
        });
        continue;
      }

      if (aHas && bHas) {
        walk(a[i], b[i], nextPath);
      }
    }
  }

  function isCircularPair(a, b, path) {
    let inner = seen.get(a);
    if (!inner) {
      inner = new WeakMap();
      seen.set(a, inner);
      inner.set(b, path);
      return false;
    }

    if (inner.has(b)) {
      return true;
    }

    inner.set(b, path);
    return false;
  }

  function valueTag(value) {
    if (value === null) return 'null';
    if (Array.isArray(value)) return 'array';
    return typeof value;
  }

  function pathJoin(base, key) {
    return isIdentifier(key)
      ? `${base}.${key}`
      : `${base}[${JSON.stringify(key)}]`;
  }

  function isIdentifier(key) {
    return /^[A-Za-z_$][A-Za-z0-9_$]*$/.test(key);
  }
}
```

